function insert_group_icons($path, $group_icons) {
    echo "Inserting group icons in $path\n";
    $content = file_get_contents($path);
    if ($content === false) {
        echo "Failed to read $path\n";
        return;
    }

    $pattern = '/(<div class="sidebar-section-title !gap-3"[^>]*>\s*)(<span class="sidebar-text[^>]*>(.*?)<\/span>)/is';

    $new_content = preg_replace_callback($pattern, function($matches) use ($group_icons) {
        $div_start = $matches[1];
        $span_block = $matches[2];
        $title = trim($matches[3]);
        
        // Remove !gap-3 !flex-grow inside span to keep spacing clean, 
        // wait, let's keep it or replace it depending on need.
        // Let's print the title found
        echo "Found section title: '$title'\n";
        
        if (isset($group_icons[$title])) {
            $icon_svg = $group_icons[$title];
            // Check if icon is already present
            if (strpos($div_start, '<svg') !== false || strpos($matches[0], 'sidebar-section-title-icon') !== false) {
                // Already has an icon, skip
                return $matches[0];
            }
            return $div_start . $icon_svg . "\n                " . $span_block;
        }
        
        return $matches[0];
    }, $content);

    if (file_put_contents($path, $new_content) !== false) {
        echo "Successfully updated $path\n";
    } else {
        echo "Failed to write $path\n";
    }
}

insert_group_icons('resources/views/vendor/tyro-dashboard/partials/admin-sidebar.blade.php', $group_icons);
